{"rawEvent":{"message_id":"019d9975e5c4758889bf677707967606","conversation_id":"019d8fed3e2a711ebf4dff4a281c6300","tool_call_id":"tooluse_JwSrGpLbDTT5MA4rDnoh8V","document":{"file_path":"/Users/junjiecui/AndroidStudioProjects/AircraftWar/app/src/main/java/edu/hitsz/aircraftwar/controller/SpawnController.kt","sub_content":"SpawnController.kt","sub_content_event":"open_editor","sub_content_event_value":"/Users/junjiecui/AndroidStudioProjects/AircraftWar/app/src/main/java/edu/hitsz/aircraftwar/controller/SpawnController.kt","sub_content_tip":"/Users/junjiecui/AndroidStudioProjects/AircraftWar/app/src/main/java/edu/hitsz/aircraftwar/controller/SpawnController.kt","apply_content":"package edu.hitsz.aircraftwar.controller

import edu.hitsz.aircraftwar.AircraftWarApplication
import edu.hitsz.aircraftwar.logic.aircraft.AbstractAircraft
import edu.hitsz.aircraftwar.logic.aircraft.BossEnemy
import edu.hitsz.aircraftwar.logic.aircraft.EliteEnemy
import edu.hitsz.aircraftwar.logic.aircraft.MobEnemy
import edu.hitsz.aircraftwar.logic.aircraft.SuperEliteEnemy
import edu.hitsz.aircraftwar.logic.factory.BossEnemyFactory
import edu.hitsz.aircraftwar.logic.factory.EliteEnemyFactory
import edu.hitsz.aircraftwar.logic.factory.MobEnemyFactory
import edu.hitsz.aircraftwar.logic.factory.PropBloodFactory
import edu.hitsz.aircraftwar.logic.factory.PropBombFactory
import edu.hitsz.aircraftwar.logic.factory.PropBulletFactory
import edu.hitsz.aircraftwar.logic.factory.PropBulletPlusFactory
import edu.hitsz.aircraftwar.logic.factory.SuperEliteEnemyFactory
import edu.hitsz.aircraftwar.model.config.GameConfig
import edu.hitsz.aircraftwar.model.entity.EntityManager
import edu.hitsz.aircraftwar.model.state.GameState
import edu.hitsz.aircraftwar.setting.Music.MusicManager
import java.util.Random

/**
 * 生成控制器 - Controller层
 * 负责敌机生成、道具生成和射击调度
 */
class SpawnController(
 private val gameConfig: GameConfig,
 private val entityManager: EntityManager,
 private val gameState: GameState
) {
 // 工厂实例
 private val mobEnemyFactory = MobEnemyFactory()
 private val eliteEnemyFactory = EliteEnemyFactory()
 private val superEliteEnemyFactory = SuperEliteEnemyFactory()
 private val bossEnemyFactory = BossEnemyFactory()
 private val propBloodFactory = PropBloodFactory()
 private val propBombFactory = PropBombFactory()
 private val propBulletFactory = PropBulletFactory()
 private val propBulletPlusFactory = PropBulletPlusFactory()

 private val random = Random()

 /**
 * 生成敌机
 */
 fun spawnEnemies() {
 if (entityManager.enemyAircrafts.size < gameConfig.enemyMaxNumber) {
 val randomNum = random.nextInt(gameConfig.enemyRate)

 // 根据随机数生成普通、精英敌机、超级精英敌机
 val enemy: AbstractAircraft? = when {
 randomNum == 0 -> superEliteEnemyFactory.createEnemy()
 randomNum == 1 || randomNum == 2 -> eliteEnemyFactory.createEnemy()
 else -> mobEnemyFactory.createEnemy()
 }

 enemy?.let {
 entityManager.enemyAircrafts.add(it)
 }
 }

 // 每300分产生一个Boss, 且场上只能有一个Boss(仅普通模式、困难模式)
 if (gameState.shouldSpawnBoss(gameConfig.difficultyStr)) {
 MusicManager.switchBossBgm()
 bossEnemyFactory.createEnemy()?.let {
 entityManager.enemyAircrafts.add(it)
 }
 gameState.markBossSpawned()
 }

 // 观察者注册最新添加的敌机
 if (entityManager.enemyAircrafts.isNotEmpty()) {
 entityManager.bombSubject.registerObserver(
 entityManager.enemyAircrafts[entityManager.enemyAircrafts.size - 1]
 )
 }
 }

 /**
 * 所有飞行器发射子弹
 */
 fun shootAll() {
 // 敌机射击
 for (enemy in entityManager.enemyAircrafts) {
 if (enemy is MobEnemy) continue // 普通敌机不射击

 val bullets = enemy.shoot()
 if (bullets != null) {
 val validBullets = bullets.filterNotNull()
 entityManager.enemyBullets.addAll(validBullets)
 for (bullet in validBullets) {
 entityManager.bombSubject.registerObserver(bullet)
 }
 }
 }

 // 英雄射击
 entityManager.heroBullets.addAll(
 entityManager.heroAircraft.shoot().filterNotNull()
 )

 // 检查火力道具时间
 entityManager.heroAircraft.checkShootModeDuration()
 }

 /**
 * 在指定位置生成道具
 */
 fun generateProp(x: Int, y: Int) {
 val randomNum = random.nextInt(gameConfig.propRate)
 when {
 randomNum in 0..<3 -> { // 30% 生成血量道具
 propBloodFactory.createProp(x, y)?.let { entityManager.props.add(it) }
 }
 randomNum in 3..<6 -> { // 30% 生成炸弹道具
 propBombFactory.createProp(x, y)?.let { entityManager.props.add(it) }
 }
 randomNum in 6..<9 -> { // 30% 生成子弹道具(两种)
 val bulletType = random.nextInt(2)
 if (bulletType == 0) {
 propBulletFactory.createProp(x, y)?.let { entityManager.props.add(it) }
 } else {
 propBulletPlusFactory.createProp(x, y)?.let { entityManager.props.add(it) }
 }
 }
 // else: 10% 不生成道具
 }
 }

 /**
 * 根据敌机类型在其位置生成道具
 */
 fun generatePropsForDestroyedEnemy(enemy: AbstractAircraft) {
 val propX = enemy.getLocationXVal()
 val propY = enemy.getLocationYVal()

 when (enemy) {
 is MobEnemy -> {
 // 普通敌机不掉落道具
 }
 is BossEnemy -> {
 // Boss掉落 <= 3个道具
 generateProp(propX, propY)
 generateProp((propX + 100) % AircraftWarApplication.SCREEN_WIDTH, propY + 20)
 generateProp((propX + 200) % AircraftWarApplication.SCREEN_WIDTH, propY + 50)
 gameState.markBossKilled()
 }
 is EliteEnemy -> {
 generateProp(propX, propY)
 }
 is SuperEliteEnemy -> {
 generateProp(propX, propY)
 }
 }
 }
}
","instruction":"创建 SpawnController 类，负责敌机生成、道具生成和射击调度逻辑，从 GameView 中提取出来。","apply_mode":"apply_only"}},"timestamp":1776396279,"type":"TOOL_CALL_ARGS"}

{"rawEvent":{"message_id":"019d9975e5c4758889bf677707967606","conversation_id":"019d8fed3e2a711ebf4dff4a281c6300","tool_call_id":"tooluse_0tAZFvkrC8EXFxkzJuN6Lu","document":{"file_path":"/Users/junjiecui/AndroidStudioProjects/AircraftWar/app/src/main/java/edu/hitsz/aircraftwar/controller/CollisionController.kt","sub_content":"CollisionController.kt","sub_content_event":"open_editor","sub_content_event_value":"/Users/junjiecui/AndroidStudioProjects/AircraftWar/app/src/main/java/edu/hitsz/aircraftwar/controller/CollisionController.kt","sub_content_tip":"/Users/junjiecui/AndroidStudioProjects/AircraftWar/app/src/main/java/edu/hitsz/aircraftwar/controller/CollisionController.kt","apply_content":"package edu.hitsz.aircraftwar.controller

import edu.hitsz.aircraftwar.logic.aircraft.BossEnemy
import edu.hitsz.aircraftwar.logic.aircraft.EliteEnemy
import edu.hitsz.aircraftwar.logic.aircraft.MobEnemy
import edu.hitsz.aircraftwar.logic.aircraft.SuperEliteEnemy
import edu.hitsz.aircraftwar.logic.prop.BaseProp
import edu.hitsz.aircraftwar.logic.prop.PropBlood
import edu.hitsz.aircraftwar.logic.prop.PropBomb
import edu.hitsz.aircraftwar.logic.prop.PropBullet
import edu.hitsz.aircraftwar.logic.prop.PropBulletPlus
import edu.hitsz.aircraftwar.model.entity.EntityManager
import edu.hitsz.aircraftwar.model.state.GameState
import edu.hitsz.aircraftwar.setting.Music.MusicManager
import edu.hitsz.aircraftwar.setting.Setting

/**
 * 碰撞检测控制器 - Controller层
 * 处理所有碰撞检测逻辑
 */
class CollisionController(
 private val entityManager: EntityManager,
 private val gameState: GameState,
 private val spawnController: SpawnController
) {

 /**
 * 执行所有碰撞检测
 */
 fun checkAllCollisions() {
 checkEnemyBulletsHitHero()
 checkHeroBulletsHitEnemy()
 checkEnemyAircraftCrashHero()
 checkHeroPickupProps()
 }

 /**
 * 敌机子弹攻击英雄
 */
 private fun checkEnemyBulletsHitHero() {
 for (bullet in entityManager.enemyBullets) {
 if (bullet.notValid()) continue
 if (entityManager.heroAircraft.crash(bullet)) {
 entityManager.heroAircraft.decreaseHp(bullet.power)
 bullet.vanish()
 }
 }
 }

 /**
 * 英雄子弹与敌机碰撞检测
 */
 private fun checkHeroBulletsHitEnemy() {
 for (bullet in entityManager.heroBullets) {
 if (bullet.notValid()) continue
 for (enemyAircraft in entityManager.enemyAircrafts) {
 if (enemyAircraft.notValid()) continue
 if (enemyAircraft.crash(bullet)) {
 MusicManager.playSound(MusicManager.SoundType.BULLET_HIT)
 enemyAircraft.decreaseHp(bullet.power)
 bullet.vanish()
 if (enemyAircraft.notValid()) {
 // 敌机被击毁，生成道具
 spawnController.generatePropsForDestroyedEnemy(enemyAircraft)
 }
 }
 }
 }
 }

 /**
 * 英雄飞机与敌机碰撞检测
 */
 private fun checkEnemyAircraftCrashHero() {
 for (enemyAircraft in entityManager.enemyAircrafts) {
 if (enemyAircraft.notValid()) continue
 if (enemyAircraft.crash(entityManager.heroAircraft) ||
 entityManager.heroAircraft.crash(enemyAircraft)) {
 enemyAircraft.vanish()
 entityManager.heroAircraft.decreaseHp(entityManager.heroAircraft.hp)
 }
 }
 }

 /**
 * 英雄拾取道具
 */
 private fun checkHeroPickupProps() {
 for (prop in entityManager.props) {
 if (prop.notValid()) continue
 if (entityManager.heroAircraft.crash(prop)) {
 MusicManager.playSound(MusicManager.SoundType.GET_PROP)
 prop.vanish()
 applyPropEffect(prop)
 }
 }
 }

 /**
 * 应用道具效果
 */
 private fun applyPropEffect(prop: BaseProp) {
 when (prop) {
 is PropBlood -> {
 entityManager.heroAircraft.increaseHp(30)
 }
 is PropBullet -> {
 entityManager.heroAircraft.changeShootMode("SCATTER")
 }
 is PropBulletPlus -> {
 entityManager.heroAircraft.changeShootMode("WAVE")
 }
 is PropBomb -> {
 if (Setting.musicOpen) {
 MusicManager.playSound(MusicManager.SoundType.BOMB_EXPLOSION)
 }
 prop.action()
 entityManager.bombSubject.notifyObservers()
 }
 }
 }
}
","instruction":"创建 CollisionController 类，处理所有碰撞检测逻辑，包括敌机子弹攻击英雄、英雄子弹攻击敌机、飞机碰撞和道具拾取。","apply_mode":"apply_only"}},"timestamp":1776396309,"type":"TOOL_CALL_ARGS"}

{"rawEvent":{"message_id":"019d9975e5c4758889bf677707967606","conversation_id":"019d8fed3e2a711ebf4dff4a281c6300","tool_call_id":"tooluse_SAhpNyZWBkPMwNFVFiga6u","document":{"file_path":"/Users/junjiecui/AndroidStudioProjects/AircraftWar/app/src/main/java/edu/hitsz/aircraftwar/controller/ScoreController.kt","sub_content":"ScoreController.kt","sub_content_event":"open_editor","sub_content_event_value":"/Users/junjiecui/AndroidStudioProjects/AircraftWar/app/src/main/java/edu/hitsz/aircraftwar/controller/ScoreController.kt","sub_content_tip":"/Users/junjiecui/AndroidStudioProjects/AircraftWar/app/src/main/java/edu/hitsz/aircraftwar/controller/ScoreController.kt","apply_content":"package edu.hitsz.aircraftwar.controller

import edu.hitsz.aircraftwar.logic.aircraft.AbstractAircraft
import edu.hitsz.aircraftwar.logic.aircraft.BossEnemy
import edu.hitsz.aircraftwar.logic.aircraft.EliteEnemy
import edu.hitsz.aircraftwar.logic.aircraft.MobEnemy
import edu.hitsz.aircraftwar.logic.aircraft.SuperEliteEnemy
import edu.hitsz.aircraftwar.model.state.GameState
import edu.hitsz.aircraftwar.setting.Music.MusicManager

/**
 * 分数控制器 - Controller层
 * 管理分数计算和游戏结束判定
 */
class ScoreController(
 private val gameState: GameState
) {

 /**
 * 处理被移除的敌机，计算分数
 * @param removedAircrafts 本帧被移除的敌机列表
 */
 fun processRemovedEntities(removedAircrafts: List<AbstractAircraft>) {
 for (aircraft in removedAircrafts) {
 when (aircraft) {
 is MobEnemy -> gameState.addScore(10)
 is EliteEnemy -> gameState.addScore(20)
 is SuperEliteEnemy -> gameState.addScore(30)
 is BossEnemy -> {
 gameState.addScore(50)
 MusicManager.switchNormalBgm()
 }
 }
 }
 }
}
